spec.inputArgumentsSchemaV2:
{
  "type": "object",
  "properties": {
    "question": {
      "type": "string",
      "description": "The basic math question to be answered (e.g., 'What is 25 * 4?', 'What is 15% of 200?', 'Solve: 3x + 5 = 20'). Must be a valid math question. Do not leave empty."
    }
  },
  "required": [
    "question"
  ]
}

spec.outputArgumentsSchemaV2:
{
  "type": "object",
  "properties": {
    "answer": {
      "type": "string",
      "description": "The final result of the math calculation or problem (e.g., '100', '42.5', 'x = 5'). If the input is not a math question, set to 'N/A'."
    },
    "steps": {
      "type": "string",
      "description": "A brief, clear explanation of how the answer was derived, showing key calculation steps. If the input is not a math question, explain that only math questions are supported."
    },
    "operation_type": {
      "type": "string",
      "description": "The type of math operation used to solve the problem (e.g., 'addition', 'subtraction', 'multiplication', 'division', 'percentage', 'algebra', 'fractions', 'exponents'). Set to 'N/A' if not applicable."
    }
  },
  "required": [
    "answer",
    "steps",
    "operation_type"
  ]
}

